#!/usr/bin/env python3
from pathlib import Path
import base64,zlib
ROOT=Path(__file__).resolve().parents[1]
INDEX=ROOT/"index.html"
STYLE_MARKER='<style id="sciwrix-ribbon-ui-styles">'
SCRIPT_MARKER='<script id="sciwrix-ribbon-ui-script">'
CSS=zlib.decompress(base64.b64decode("")).decode("utf-8")
JS=zlib.decompress(base64.b64decode("")).decode("utf-8")
def fail(m): raise SystemExit("Ribbon UI patch aborted: "+m)
def main():
    if not INDEX.exists(): fail(f"{INDEX} does not exist")
    text=INDEX.read_text(encoding="utf-8")
    hs,hj=STYLE_MARKER in text,SCRIPT_MARKER in text
    if hs and hj:
        print("Revised ribbon UI is already present; no changes required."); return
    if hs!=hj: fail("only one ribbon marker is present; refusing a partial repair")
    required=["</head>","</body>",'id="fileInput"','id="downloadBtn"','id="saveAsBtn"','id="printBtn"','id="fullscreenBtn"','id="editor"','id="wysiwygEditor"']
    missing=[m for m in required if m not in text]
    if missing: fail("expected current-app markers were not found: "+", ".join(missing))
    if "Sciwrix" not in text: fail("the file does not appear to be the current Sciwrix app")
    text=text.replace("</head>",CSS+"\n</head>",1)
    pos=text.rfind("</body>")
    if pos<0: fail("closing body marker disappeared during patching")
    text=text[:pos]+JS+"\n"+text[pos:]
    if text.count(STYLE_MARKER)!=1 or text.count(SCRIPT_MARKER)!=1: fail("marker count is not exactly one after patching")
    INDEX.write_text(text,encoding="utf-8")
    print("Applied revised Sciwrix ribbon UI to index.html")
if __name__=="__main__": main()
